func frontParseDiagnosticKindByName(name string) FrontParseDiagnosticKind {
	return func() FrontParseDiagnosticKind {
		if name == "unexpected" {
			return FrontParseDiagnosticKind(&FrontParseDiagnosticKind_FrontParseDiagUnexpectedToken{})
		} else if name == "missingName" {
			return FrontParseDiagnosticKind(&FrontParseDiagnosticKind_FrontParseDiagMissingName{})
		} else if name == "missingDelimiter" {
			return FrontParseDiagnosticKind(&FrontParseDiagnosticKind_FrontParseDiagMissingDelimiter{})
		} else if name == "unmatchedDelimiter" {
			return FrontParseDiagnosticKind(&FrontParseDiagnosticKind_FrontParseDiagUnmatchedDelimiter{})
		} else if name == "nonAssoc" {
			return FrontParseDiagnosticKind(&FrontParseDiagnosticKind_FrontParseDiagNonAssociativeOperator{})
		} else if name == "trailingSelector" {
			return FrontParseDiagnosticKind(&FrontParseDiagnosticKind_FrontParseDiagTrailingSelector{})
		} else {
			return FrontParseDiagnosticKind(&FrontParseDiagnosticKind_FrontParseDiagLexerError{})
		}
	}()
}

